[data-theme='dark'] {
  /* Invert surface tokens */
  --tatva-color-bg: #0f172a;
  --tatva-color-bg-subtle: #1e293b;
  --tatva-color-fg: #f8fafc;
  --tatva-color-fg-muted: #cbd5e1;
  --tatva-color-border: #334155;
  --tatva-color-border-strong: #475569;
  --tatva-color-overlay: rgba(0, 0, 0, 0.7);

  /* Adjust semantic backgrounds for darker theme */
  --tatva-color-success-bg: #14532d;
  --tatva-color-error-bg: #7f1d1d;
  --tatva-color-warning-bg: #78350f;
  --tatva-color-info-bg: #075985;

  /* Slightly stronger shadows on dark bg */
  --tatva-shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.4);
  --tatva-shadow-md:
    0 4px 6px -1px rgba(0, 0, 0, 0.5), 0 2px 4px -2px rgba(0, 0, 0, 0.5);
  --tatva-shadow-lg:
    0 10px 15px -3px rgba(0, 0, 0, 0.6), 0 4px 6px -4px rgba(0, 0, 0, 0.6);
}
